const { GoogleGenerativeAI } = require('@google/generative-ai');
require('dotenv').config();
const fs = require('fs');

// Create a valid 100x100 red jpeg base64 string
const validJpegBase64 = "";

async function test(modelName) {
  try {
    const genAI = new GoogleGenerativeAI(process.env.GEMINI_API_KEY);
    const model = genAI.getGenerativeModel({ model: modelName });
    const imagePart = { inlineData: { data: validJpegBase64, mimeType: 'image/jpeg' } };
    const prompt = `Analyze this red image. Return JSON {"color": "red"}`;
    const result = await model.generateContent([prompt, imagePart]);
    console.log(`Success ${modelName}`);
  } catch (err) {
    console.error(`Error ${modelName}:`, err.message);
  }
}

async function run() {
  await test("gemini-2.5-flash");
  await test("gemini-1.5-flash");
}
run();
